(function(w){"use strict";
function e(v){return String(v==null?"":v).replace(/[&<>\"]/g,function(c){return {"&":"&amp;","<":"&lt;",">":"&gt;","\"":"&quot;"}[c]||c;});}
function renderField(f){var a=' data-key="'+e(f.key)+'"';if(f.raw)a+=' data-raw="1"';if(f.type==='select'){return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><select class="hm-calc-select"'+a+'>'+f.options.map(function(o){return '<option value="'+e(o[0])+'"'+(String(o[0])===String(f.default)?' selected':'')+'>'+e(o[1])+'</option>';}).join('')+'</select></div>';}if(f.type==='textarea'){return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><textarea class="hm-calc-input" rows="4"'+a+' placeholder="'+e(f.placeholder||'')+'">'+e(f.default||'')+'</textarea></div>';}var type=f.type==='date'?'date':'text';var mode=f.type==='integer'?'numeric':'decimal';return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><input class="hm-calc-input" type="'+type+'" inputmode="'+mode+'"'+a+' placeholder="'+e(f.placeholder||'')+'" value="'+e(f.default||'')+'"></div>';}
function makeRender(def){return function(root,api){var html='<div class="hm-calc-panel"><div class="hm-calc-form">';if(def.hint)html+='<p class="hm-calc-hint">'+e(def.hint)+'</p>';html+='<div class="hm-calc-grid-2">'+def.fields.map(renderField).join('')+'</div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">계산하기</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>';root.innerHTML=html;var els=Array.prototype.slice.call(root.querySelectorAll('[data-key]')),go=root.querySelector('button'),msg=root.querySelector('.hm-calc-message'),res=root.querySelector('.hm-calc-result');go.addEventListener('click',function(){var x={};els.forEach(function(el){var k=el.getAttribute('data-key');if(el.tagName==='SELECT'||el.getAttribute('data-raw')==='1'||el.type==='date')x[k]=el.value;else x[k]=api.parseNumber(el.value);});var r=def.compute(x);if(r&&r.error){api.setMessage(msg,r.error);api.clearResult(res);return;}api.setMessage(msg,'');api.setResult(res,def.format(r,api));});};}
var defs=[{id:"geometric-mean-list",fields:[{"key":"values","label":"숫자 목록","type":"textarea","placeholder":"예: 1, 4, 16","default":"","options":[],"raw":true}],hint:"",compute:function(x){var a=String(x.values||"").trim().split(/[\s,;]+/).filter(Boolean).map(Number);if(!a.length||!a.every(Number.isFinite)||a.some(function(v){return v<0;}))return{error:"0 이상의 숫자를 쉼표나 공백으로 구분해 입력해 주세요."};var zero=a.some(function(v){return v===0;}),g=zero?0:Math.exp(a.reduce(function(s,v){return s+Math.log(v);},0)/a.length);return{count:a.length,geometricMean:g,minValue:Math.min.apply(null,a),maxValue:Math.max.apply(null,a)};},format:function(r,api){return api.resultCard("기하평균",api.formatNumber(r.geometricMean,6),"자료 "+r.count+"개")+api.resultCard("범위",api.formatNumber(r.minValue,4)+" ~ "+api.formatNumber(r.maxValue,4),"");}},{id:"harmonic-mean-list",fields:[{"key":"values","label":"양수 목록","type":"textarea","placeholder":"예: 2, 3, 6","default":"","options":[],"raw":true}],hint:"",compute:function(x){var a=String(x.values||"").trim().split(/[\s,;]+/).filter(Boolean).map(Number);if(!a.length||!a.every(Number.isFinite)||a.some(function(v){return v<=0;}))return{error:"0보다 큰 숫자를 쉼표나 공백으로 구분해 입력해 주세요."};var h=a.length/a.reduce(function(s,v){return s+1/v;},0);return{count:a.length,harmonicMean:h,arithmeticMean:a.reduce(function(s,v){return s+v;},0)/a.length};},format:function(r,api){return api.resultCard("조화평균",api.formatNumber(r.harmonicMean,6),"자료 "+r.count+"개")+api.resultCard("산술평균 비교",api.formatNumber(r.arithmeticMean,6),"");}},{id:"root-mean-square-list",fields:[{"key":"values","label":"숫자 목록","type":"textarea","placeholder":"예: 1, 4, 16","default":"","options":[],"raw":true}],hint:"",compute:function(x){var a=String(x.values||"").trim().split(/[\s,;]+/).filter(Boolean).map(Number);if(!a.length||!a.every(Number.isFinite))return{error:"숫자를 쉼표나 공백으로 구분해 입력해 주세요."};var rms=Math.sqrt(a.reduce(function(s,v){return s+v*v;},0)/a.length),ma=a.reduce(function(s,v){return s+Math.abs(v);},0)/a.length;return{count:a.length,rms:rms,meanAbsolute:ma};},format:function(r,api){return api.resultCard("RMS",api.formatNumber(r.rms,6),"자료 "+r.count+"개")+api.resultCard("평균 절댓값",api.formatNumber(r.meanAbsolute,6),"");}},{id:"covariance-correlation",fields:[{"key":"xValues","label":"X 숫자 목록","type":"textarea","placeholder":"예: 1, 2, 3, 4","default":"","options":[],"raw":true},{"key":"yValues","label":"Y 숫자 목록","type":"textarea","placeholder":"예: 2, 4, 5, 8","default":"","options":[],"raw":true}],hint:"",compute:function(x){function p(v){return String(v||"").trim().split(/[\s,;]+/).filter(Boolean).map(Number);}var a=p(x.xValues),b=p(x.yValues);if(a.length<2||a.length!==b.length||!a.every(Number.isFinite)||!b.every(Number.isFinite))return{error:"X와 Y에 같은 개수의 숫자를 2개 이상 입력해 주세요."};var n=a.length,mx=a.reduce(function(s,v){return s+v;},0)/n,my=b.reduce(function(s,v){return s+v;},0)/n,c=0,vx=0,vy=0;for(var i=0;i<n;i++){var dx=a[i]-mx,dy=b[i]-my;c+=dx*dy;vx+=dx*dx;vy+=dy*dy;}if(vx===0||vy===0)return{error:"두 목록 모두 값의 변화가 있어야 상관계수를 계산할 수 있습니다."};c/=n;return{count:n,covariance:c,correlation:c/Math.sqrt(vx/n*vy/n),meanX:mx,meanY:my};},format:function(r,api){return api.resultCard("피어슨 상관계수",api.formatNumber(r.correlation,6),"자료 쌍 "+r.count+"개")+api.resultCard("모집단 공분산",api.formatNumber(r.covariance,6),"X 평균 "+api.formatNumber(r.meanX,4)+" · Y 평균 "+api.formatNumber(r.meanY,4));}},{id:"linear-regression-list",fields:[{"key":"xValues","label":"X 숫자 목록","type":"textarea","placeholder":"예: 1, 2, 3, 4","default":"","options":[],"raw":true},{"key":"yValues","label":"Y 숫자 목록","type":"textarea","placeholder":"예: 2, 4, 5, 8","default":"","options":[],"raw":true}],hint:"",compute:function(x){function p(v){return String(v||"").trim().split(/[\s,;]+/).filter(Boolean).map(Number);}var a=p(x.xValues),b=p(x.yValues);if(a.length<2||a.length!==b.length||!a.every(Number.isFinite)||!b.every(Number.isFinite))return{error:"X와 Y에 같은 개수의 숫자를 2개 이상 입력해 주세요."};var n=a.length,mx=a.reduce(function(s,v){return s+v;},0)/n,my=b.reduce(function(s,v){return s+v;},0)/n,sxx=0,sxy=0,syy=0;for(var i=0;i<n;i++){var dx=a[i]-mx,dy=b[i]-my;sxx+=dx*dx;sxy+=dx*dy;syy+=dy*dy;}if(sxx===0)return{error:"X 값에 변화가 있어야 회귀식을 계산할 수 있습니다."};var slope=sxy/sxx,intercept=my-slope*mx,r2=syy===0?1:sxy*sxy/(sxx*syy);return{count:n,slope:slope,intercept:intercept,rSquared:r2};},format:function(r,api){return api.resultCard("회귀식", "y = "+api.formatNumber(r.slope,6)+"x + "+api.formatNumber(r.intercept,6),"자료 쌍 "+r.count+"개")+api.resultCard("결정계수 R²",api.formatNumber(r.rSquared,6),"");}},{id:"z-score",fields:[{"key":"value","label":"관측값","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"mean","label":"평균","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"standardDeviation","label":"표준편차","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var v=Number(x.value),m=Number(x.mean),s=Number(x.standardDeviation);if(![v,m,s].every(Number.isFinite)||s<=0)return{error:"관측값과 평균은 숫자, 표준편차는 0보다 크게 입력해 주세요."};return{zScore:(v-m)/s,difference:v-m,standardDeviation:s};},format:function(r,api){return api.resultCard("Z점수",api.formatNumber(r.zScore,6),"평균과의 차이 "+api.formatNumber(r.difference,4))+api.resultCard("표준편차",api.formatNumber(r.standardDeviation,4),"");}}];defs.forEach(function(def){w.HM_CALC.register(def.id,{compute:def.compute,render:makeRender(def)});});})(window);
